import{_ as t,o,c as a,a0 as r}from"./chunks/framework.jwovEGr5.js";const n="data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAYAAAAfFcSJAAAADUlEQVR4nGMAAQAABQABDQottAAAAABJRU5ErkJggg==",p=JSON.parse('{"title":"Finding Your Way Around","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/navigating.md","filePath":"getting-started/navigating.md"}'),s={name:"getting-started/navigating.md"};function i(h,e,d,l,g,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="finding-your-way-around" tabindex="-1">Finding Your Way Around <a class="header-anchor" href="#finding-your-way-around" aria-label="Permalink to &quot;Finding Your Way Around&quot;">​</a></h1><p>Once you&#39;re logged in, the app has three main areas: the <strong>sidebar</strong> on the left (where you go), the <strong>top bar</strong> across the top (who and where you are, plus quick tools), and the <strong>main area</strong> in the middle (what you&#39;re working on). What you see is shaped by your <a href="./../roles/overview.html">role</a> — lower roles simply have fewer menu items.</p><p><img src="'+n+'" alt="Sidebar for a leader vs. a supreme admin"></p><h2 id="the-sidebar-left" tabindex="-1">The sidebar (left) <a class="header-anchor" href="#the-sidebar-left" aria-label="Permalink to &quot;The sidebar (left)&quot;">​</a></h2><p>The sidebar groups pages into sections. You&#39;ll only see the sections your role can use, so your sidebar may be shorter than a colleague&#39;s — that&#39;s normal, not a bug.</p><table tabindex="0"><thead><tr><th>Section</th><th>What lives here</th><th>Who typically sees it</th></tr></thead><tbody><tr><td><strong>Main</strong></td><td>Dashboard, Analytics, Players, Event Templates, Event Instances, KvK Prep, Records, Rewards</td><td>Everyone (view‑only for Alliance Players)</td></tr><tr><td><strong>Input</strong></td><td>Manual Input, Imports, Reports</td><td>Roles that can enter or upload data</td></tr><tr><td><strong>Management</strong></td><td>Users, Kingdoms, <strong>My Alliance</strong>, Roles, Permissions</td><td>Kings, Leaders, Supreme Admins</td></tr><tr><td><strong>Settings</strong></td><td>Event Settings, Player Attributes, Reward Rules, Support &amp; Plans, Image Processing, Email, Theme</td><td>Depends on the setting; some are admin‑only</td></tr><tr><td><strong>Admin</strong></td><td>Registration/Password/Restore requests, Logs, Icons, Recycle Bin, Subscriptions &amp; Usage, Support Links</td><td>Senior roles; several are Supreme‑Admin‑only</td></tr></tbody></table><p>A few notes:</p><ul><li><strong>Alliance Leaders and Co‑Leaders</strong> get a <strong>My Alliance</strong> entry as their management home, instead of the kingdom‑wide Kingdoms list.</li><li><strong>Supreme‑Admin‑only</strong> areas (like the platform Subscriptions &amp; Usage manager and Support Links) won&#39;t appear for anyone else.</li><li>If a menu item isn&#39;t there, your role doesn&#39;t have access to it. See <a href="./access-denied.html">&quot;You don&#39;t have access&quot;</a>.</li></ul><h2 id="the-top-bar-top" tabindex="-1">The top bar (top) <a class="header-anchor" href="#the-top-bar-top" aria-label="Permalink to &quot;The top bar (top)&quot;">​</a></h2><p>The top bar shows and controls a few things:</p><ul><li><strong>Your current kingdom and role</strong> — on the left, so you always know where you&#39;re working.</li><li><strong>Image‑processing status chip</strong> — shows whether you&#39;re using Free Local processing or Gemini Premium, and whether it&#39;s ready. Selecting it opens the image‑processing settings (if your role can change them).</li><li><strong>Reports</strong> shortcut, your <strong>name/profile</strong>, and <strong>Logout</strong> — on the right.</li><li><strong>Light / Dark theme toggle</strong> — see below.</li></ul><h2 id="the-context-banner-—-knowing-where-you-are" tabindex="-1">The context banner — knowing <em>where</em> you are <a class="header-anchor" href="#the-context-banner-—-knowing-where-you-are" aria-label="Permalink to &quot;The context banner — knowing *where* you are&quot;">​</a></h2><p>Just under the top bar is a <strong>context banner</strong> that reads something like:</p><blockquote><p>Current context: <em>Kingdom Name / [TAG]</em> — Role: <em>Alliance Leader</em></p></blockquote><p>This tells you which kingdom and alliance your actions currently apply to, and which role you&#39;re acting as. It&#39;s important because the app only shows and changes data inside your current context — if a player or event seems &quot;missing,&quot; first check you&#39;re in the right context.</p><p>If your kingdom or alliance is close to its storage limit, a warning also appears here.</p><blockquote><p><strong>Multiple roles?</strong> The banner reflects your active assignment. If you hold roles in more than one place, be aware that what you see is scoped to your current context. (Holding multiple roles is covered in the roles section.)</p></blockquote><h2 id="switching-between-light-and-dark-mode" tabindex="-1">Switching between Light and Dark mode <a class="header-anchor" href="#switching-between-light-and-dark-mode" aria-label="Permalink to &quot;Switching between Light and Dark mode&quot;">​</a></h2><p>Use the <strong>theme toggle</strong> in the top bar to switch between <strong>Light</strong> and <strong>Dark</strong> appearance. The choice is yours and is remembered for you. (There are no additional color themes — just Light and Dark.)</p><h2 id="getting-back-to-the-dashboard" tabindex="-1">Getting back to the dashboard <a class="header-anchor" href="#getting-back-to-the-dashboard" aria-label="Permalink to &quot;Getting back to the dashboard&quot;">​</a></h2><p>Selecting <strong>Dashboard</strong> in the Main section always returns you to your home screen. See <a href="./dashboard-tour.html">Reading the Dashboard</a> for what it&#39;s showing you.</p>',21)])])}const m=t(s,[["render",i]]);export{p as __pageData,m as default};
